    mHdltvoutHandle.close();
    delete conv1_U0;
    delete maxpool1_U0;
    delete conv2_U0;
    delete maxpool2_U0;
    delete conv3_U0;
    delete conv4_U0;
    delete conv5_U0;
    delete detection_head_U0;
    delete f1_local_channel_U;
    delete p1_local_channel_U;
    delete f2_local_channel_U;
